    titleEn: "Eating Out", titleAr: "تناول الطعام في الخارج",
    subtitle: "Order food and talk about your meal.",
    caption: "Could I have the bill, please?",
    vocab: [{"en":"menu","ar":"قائمة الطعام"},{"en":"waiter","ar":"نادل"},{"en":"starter","ar":"مقبلات"},{"en":"main course","ar":"طبق رئيسي"},{"en":"dessert","ar":"حلوى"},{"en":"bill","ar":"فاتورة"}],
    sentences: [{"en":"I had soup as a starter and chicken as a main course.","ar":"تناولتُ حساءً كمُقبلات ودجاجًا كطبق رئيسي."},{"en":"The waiter was friendly, but the food came late.","ar":"كان النادل ودودًا، لكن الطعام تأخر."},{"en":"We did not order dessert because we were full.","ar":"لم نطلب حلوى لأننا كنا شبعانين."},{"en":"Could we have the bill, please?","ar":"هل يمكننا الحصول على الفاتورة، من فضلك؟"}],
    conversation: [{"p":"A","t":"Are you ready to order?","ar":"هل أنت مستعد للطلب؟"},{"p":"B","t":"Yes, I will have the grilled fish, please.","ar":"نعم، سآخذ السمك المشوي، من فضلك."},{"p":"A","t":"Would you like a drink?","ar":"هل ترغب في مشروب؟"},{"p":"B","t":"Just water, thank you.","ar":"ماء فقط، شكرًا لك."}],
    story: [{"en":"Last Friday, Layla and her friend went to a new restaurant.","ar":"الجمعة الماضية، ذهبت ليلى وصديقتها إلى مطعم جديد."},{"en":"They tried the grilled chicken and a small salad.","ar":"جربتا الدجاج المشوي وسلطة صغيرة."},{"en":"The food was good, but it was a little expensive.","ar":"كان الطعام جيدًا، لكنه كان غاليًا بعض الشيء."},{"en":"They are going to come back next month for a special dinner.","ar":"سيعودان الشهر القادم لتناول عشاء خاص."}],
    grammar: {"titleEn":"Polite requests — 'Could / Would'","titleAr":"الطلبات المهذبة","lines":["Could I have the menu, please?","Would you like some water?","Could we sit by the window?","Would you bring the bill, please?"]},
