    subtitle: "Describe simple symptoms and follow advice.",
    caption: "Rest, water, and a smile.",
    vocab: [{"en":"headache","ar":"صداع"},{"en":"fever","ar":"حمى"},{"en":"cough","ar":"سعال"},{"en":"medicine","ar":"دواء"},{"en":"rest","ar":"راحة"},{"en":"appointment","ar":"موعد"}],
    sentences: [{"en":"I have a headache and a small fever, so I will rest at home.","ar":"لدي صداع وحمى خفيفة، لذلك سأستريح في المنزل."},{"en":"She took her medicine and felt better in the evening.","ar":"تناولت دوائها وشعرت بتحسن في المساء."},{"en":"He should drink more water because the weather is hot.","ar":"يجب عليه شرب المزيد من الماء لأن الطقس حار."},{"en":"I am going to make an appointment with the doctor tomorrow.","ar":"سأحدد موعدًا مع الطبيب غدًا."}],
    conversation: [{"p":"A","t":"How can I help you?","ar":"كيف يمكنني مساعدتك؟"},{"p":"B","t":"I have a strong cough and a sore throat.","ar":"لدي سعال قوي والتهاب في الحلق."},{"p":"A","t":"How long have you felt like this?","ar":"منذ متى تشعر بهذا؟"},{"p":"B","t":"For two days.","ar":"لمدة يومين."}],
    story: [{"en":"Last Monday, Hassan did not feel well at work.","ar":"يوم الاثنين الماضي، لم يكن حسن يشعر بخير في العمل."},{"en":"He had a headache, so he went home early.","ar":"كان لديه صداع، لذلك عاد إلى المنزل مبكرًا."},{"en":"His wife made hot tea and he took some medicine.","ar":"صنعت زوجته شايًا ساخنًا وتناول بعض الدواء."},{"en":"The next day, he was much better and went back to work.","ar":"في اليوم التالي، كان أفضل بكثير وعاد إلى العمل."}],
    grammar: {"titleEn":"'should' for advice","titleAr":"النصيحة بـ should","lines":["You should rest for two days.","She should drink more water.","We should not eat heavy food now.","Should I take this medicine after meals?"]},
    writing: {"en":"Write 3 sentences giving advice to a sick friend.","ar":"اكتب 3 جمل تنصح فيها صديقا مريضا."},
    tip: {"en":"After 'should', use the base verb (no 'to').","ar":"بعد should نستخدم الفعل المجرد."},
