    vocab: [{"en":"engineer","ar":"مهندس"},{"en":"nurse","ar":"ممرضة"},{"en":"teacher","ar":"معلمة"},{"en":"chef","ar":"طاه"},{"en":"driver","ar":"سائق"},{"en":"salary","ar":"راتب"}],
    sentences: [{"en":"My brother is an engineer and he works for a big company.","ar":"أخي مهندس ويعمل في شركة كبيرة."},{"en":"Nurses work hard, but their job is very important.","ar":"الممرضات يعملن بجد، لكن وظيفتهن مهمة جداً."},{"en":"She wants to be a teacher because she likes children.","ar":"هي تريد أن تصبح معلمة لأنها تحب الأطفال."},{"en":"I am going to apply for a new job next month.","ar":"سأتقدم بطلب لوظيفة جديدة الشهر القادم."}],
    conversation: [{"p":"A","t":"What does your father do?","ar":"ماذا يعمل والدك؟"},{"p":"B","t":"He is a chef in a small restaurant.","ar":"إنه طباخ في مطعم صغير."},{"p":"A","t":"Does he enjoy his job?","ar":"هل يستمتع بعمله؟"},{"p":"B","t":"Yes, he loves cooking for people.","ar":"نعم، هو يحب الطبخ للناس."}],
    story: [{"en":"Noor finished university last year and started her first job.","ar":"أنهت نور الجامعة العام الماضي وبدأت وظيفتها الأولى."},{"en":"She works as a nurse in a small hospital near her home.","ar":"هي تعمل كممرضة في مستشفى صغير بالقرب من منزلها."},{"en":"The job is hard, but she helps many people every day.","ar":"العمل صعب، لكنها تساعد الكثير من الناس كل يوم."},{"en":"Next year, she is going to study for a higher degree.","ar":"في العام القادم، ستدرس للحصول على شهادة أعلى."}],
    grammar: {"titleEn":"'want to' + verb","titleAr":"want to + الفعل","lines":["I want to become a teacher.","She wants to work abroad.","We do not want to change our job now.","Do you want to study English more?"]},
    writing: {"en":"Write 3 sentences about a job you want and why.","ar":"اكتب 3 جمل عن وظيفة تريدها ولماذا."},
    tip: {"en":"After 'want', use 'to' + base verb.","ar":"بعد want نستخدم to + الفعل."},
