    subtitle: "Share your plans for next month and next year.",
    caption: "Plan, save, achieve.",
    vocab: [{"en":"goal","ar":"هدف"},{"en":"plan","ar":"خطة"},{"en":"save money","ar":"ادخار"},{"en":"learn a skill","ar":"تعلم مهارة"},{"en":"future","ar":"المستقبل"},{"en":"dream","ar":"حلم"}],
    sentences: [{"en":"My main goal is to learn English well this year.","ar":"هدفي الرئيسي هو تعلم اللغة الإنجليزية جيدًا هذا العام."},{"en":"I am going to save money to buy a car.","ar":"سأوفر المال لشراء سيارة."},{"en":"She will travel to Europe because she loves history.","ar":"ستسافر إلى أوروبا لأنها تحب التاريخ."},{"en":"We are going to study a new skill every month.","ar":"سنتعلم مهارة جديدة كل شهر."}],
    conversation: [{"p":"A","t":"What are your plans for next year?","ar":"ما هي خططك للعام القادم؟"},{"p":"B","t":"I am going to start a small business.","ar":"سأبدأ عملاً تجاريًا صغيرًا."},{"p":"A","t":"That sounds great. Will you need help?","ar":"هذا يبدو رائعًا. هل ستحتاج إلى مساعدة؟"},{"p":"B","t":"Yes, maybe from my brother.","ar":"نعم، ربما من أخي."}],
    story: [{"en":"Layla wants to be a translator in the future.","ar":"ليلى تريد أن تكون مترجمة في المستقبل."},{"en":"She studies English every evening because she has a clear goal.","ar":"تدرس الإنجليزية كل مساء لأن لديها هدفًا واضحًا."},{"en":"Last month, she started reading short stories in English.","ar":"في الشهر الماضي، بدأت بقراءة قصص قصيرة باللغة الإنجليزية."},{"en":"Next year, she is going to take an international exam.","ar":"في العام القادم، ستقدم امتحانًا دوليًا."}],
    grammar: {"titleEn":"'will' for predictions","titleAr":"will للتنبؤ","lines":["I think I will pass the exam.","She will not be late tomorrow.","We will visit you next weekend.","Will you help me, please?"]},
    writing: {"en":"Write 4 sentences about your goals for this year.","ar":"اكتب 4 جمل عن أهدافك لهذه السنة."},
    tip: {"en":"Use 'will' for promises, 'going to' for plans.","ar":"استخدم will للوعود وgoing to للخطط."},
