    titleEn: "Music & Concerts", titleAr: "الموسيقى والحفلات",
    subtitle: "Talk about music styles and live events.",
    caption: "Loud, alive, unforgettable.",
    vocab: [{"en":"concert","ar":"حفلة"},{"en":"singer","ar":"مغني"},{"en":"band","ar":"فرقة"},{"en":"ticket","ar":"تذكرة"},{"en":"loud","ar":"عالي"},{"en":"audience","ar":"جمهور"}],
    sentences: [{"en":"I went to a great concert last Saturday and I really enjoyed it.","ar":"ذهبت إلى حفل موسيقي رائع السبت الماضي واستمتعت به حقًا."},{"en":"The singer was amazing, but the music was very loud.","ar":"كان المغني مذهلاً، لكن الموسيقى كانت صاخبة جدًا."},{"en":"She bought two tickets, so we are going together.","ar":"اشترت تذكرتين، لذا سنذهب معًا."},{"en":"We are going to watch a jazz band next month.","ar":"سنذهب لمشاهدة فرقة جاز الشهر القادم."}],
    conversation: [{"p":"A","t":"Do you like live music?","ar":"هل تحب الموسيقى الحية؟"},{"p":"B","t":"Yes, I love concerts.","ar":"نعم، أنا أحب الحفلات الموسيقية."},{"p":"A","t":"Have you been to one this year?","ar":"هل ذهبت إلى أحدها هذا العام؟"},{"p":"B","t":"Yes, I saw a rock band in May.","ar":"نعم، رأيت فرقة روك في مايو."}],
    story: [{"en":"Last summer, Lina went to her first big concert in the city.","ar":"في الصيف الماضي، ذهبت لينا إلى أول حفل موسيقي كبير لها في المدينة."},{"en":"The audience was huge and everyone sang together.","ar":"كان الجمهور غفيرًا والجميع غنى معًا."},{"en":"She did not sleep that night because she was so excited.","ar":"لم تنم تلك الليلة لأنها كانت متحمسة جدًا."},{"en":"Next year, she is going to a music festival with her friends.","ar":"في العام القادم، ستذهب إلى مهرجان موسيقي مع أصدقائها."}],
    grammar: {"titleEn":"Present Perfect — experience","titleAr":"المضارع التام للخبرة","lines":["I have seen this band twice.","She has never been to a concert.","We have visited many cities.","Have you ever met a singer?"]},
    writing: {"en":"Write 3 sentences about a concert or your favourite music.","ar":"اكتب 3 جمل عن حفلة أو الموسيقى المفضلة لديك."},
    tip: {"en":"Use 'ever' in questions and 'never' for no experience.","ar":"استخدم ever في السؤال وnever للنفي."},
