    titleEn: "Friends & Relationships", titleAr: "الأصدقاء والعلاقات",
    subtitle: "Talk about friends and time together.",
    caption: "True friendship lasts.",
    vocab: [{"en":"friend","ar":"صديق"},{"en":"trust","ar":"ثقة"},{"en":"kind","ar":"لطيف"},{"en":"share","ar":"يشارك"},{"en":"argue","ar":"يتجادل"},{"en":"apologise","ar":"يعتذر"}],
    sentences: [{"en":"My best friend lives near me, so we meet almost every day.","ar":"صديقي المفضل يسكن بالقرب مني، لذلك نلتقي كل يوم تقريباً."},{"en":"We had a small argument last week, but we made up quickly.","ar":"تشاجرنا شجاراً بسيطاً الأسبوع الماضي، لكن تصالحنا بسرعة."},{"en":"She is very kind because she always helps her friends.","ar":"هي لطيفة جداً لأنها دائماً تساعد أصدقاءها."},{"en":"We are going to meet at the café this evening.","ar":"سنلتقي في المقهى هذا المساء."}],
    conversation: [{"p":"A","t":"How long have you known your best friend?","ar":"منذ متى تعرف صديقك المفضل؟"},{"p":"B","t":"For ten years.","ar":"منذ عشر سنوات."},{"p":"A","t":"That is amazing. Do you see her often?","ar":"هذا رائع. هل تراها كثيراً؟"},{"p":"B","t":"Yes, almost every weekend.","ar":"نعم، كل نهاية أسبوع تقريباً."}],
    story: [{"en":"Karim and Ali have been friends since high school.","ar":"كريم وعلي صديقان منذ المدرسة الثانوية."},{"en":"Last year, they had a problem and did not talk for a month.","ar":"في العام الماضي، واجها مشكلة ولم يتحدثا لمدة شهر."},{"en":"Karim apologised first because he wanted to keep the friendship.","ar":"اعتذر كريم أولاً لأنه أراد الحفاظ على الصداقة."},{"en":"Now, they are stronger friends and meet every weekend.","ar":"الآن، هما صديقان أقوى ويلتقيان كل نهاية أسبوع."}],
